-- Strict-predecessor operator on `G` under order `lt`, evaluated at node `v`; returns a `Set Node`.
def Pred (G : CDMG Node) (lt : Node ŌåÆ Node ŌåÆ Prop) (v : Node) : Set Node :=
  -- Set-builder: nodes `w` lying in `G` (i.e.\ `G.J Ōł¬ G.V`) and strictly before `v` under `lt`.
  {w | w Ōłł G Ōł¦ lt w v}

-- Non-strict-predecessor variant (`LE` suffix): strict `Pred` together with `v` itself.
def PredLE (G : CDMG Node) (lt : Node ŌåÆ Node ŌåÆ Prop) (v : Node) : Set Node :=
  -- Take the strict predecessor set and union in the singleton `{v}` via `Set.union`.
  G.Pred lt v Ōł¬ {v}
